    if (n.includes(`forecast`) || n.includes(`week`) || n.includes(`day`) || n.includes(`predict`)) return `forecast`;
    if (n.includes(`rain`) || n.includes(`monsoon`) || n.includes(`precipitation`)) return `rainfall`;
    if (n.includes(`alert`) || n.includes(`warning`) || n.includes(`heatwave`) || n.includes(`danger`)) return `alerts`;
